import{_ as a,o as e,c as i,a2 as n}from"./chunks/framework.D5wUhsuj.js";const g=JSON.parse('{"title":"Domain & SSL Issues","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/domain-ssl.md","filePath":"troubleshooting/domain-ssl.md"}'),t={name:"troubleshooting/domain-ssl.md"};function l(r,s,o,p,h,d){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="domain-ssl-issues" tabindex="-1">Domain &amp; SSL Issues <a class="header-anchor" href="#domain-ssl-issues" aria-label="Permalink to &quot;Domain &amp; SSL Issues&quot;">​</a></h1><h2 id="dns-not-resolving" tabindex="-1">DNS not resolving <a class="header-anchor" href="#dns-not-resolving" aria-label="Permalink to &quot;DNS not resolving&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common</span> &quot;This site can&#39;t be reached&quot; or a <code>DNS_PROBE_FINISHED_NXDOMAIN</code> browser error almost always means the domain&#39;s DNS isn&#39;t pointed at your server yet, or hasn&#39;t propagated.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><strong>Prints nothing</strong> → the <code>A</code> record isn&#39;t set, or hasn&#39;t propagated yet. Check your DNS provider&#39;s dashboard.</li><li><strong>Prints the wrong IP</strong> → the <code>A</code> record points somewhere else (an old host, a placeholder). Update it to your AidiPanel server&#39;s IP.</li><li><strong>Prints the right IP, but the site still won&#39;t load</strong> → DNS is fine; the problem is on the server. See <a href="/docs/troubleshooting/server-errors">Server &amp; Gateway Errors</a>.</li></ul><p>Propagation is usually minutes, occasionally up to 24–48 hours depending on your registrar and the previous record&#39;s TTL. If you&#39;re actively working on a migration, <a href="/docs/tutorials/migrating-from-other-panels#pre-migration-checklist">lowering TTL ahead of time</a> avoids most of this wait.</p><h2 id="browser-warning-on-the-panel-port-8443" tabindex="-1">Browser warning on the panel (port 8443) <a class="header-anchor" href="#browser-warning-on-the-panel-port-8443" aria-label="Permalink to &quot;Browser warning on the panel (port 8443)&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common, and expected</span> This is not a bug. The panel&#39;s own login UI uses a <strong>self-signed certificate</strong> until you attach a real domain to it — see <a href="/docs/guide/ssl#self-signed-certificate-initial-setup">SSL / TLS → Self-signed certificate</a>. Click <strong>Advanced → Proceed</strong> (exact wording varies by browser) to reach the login page. This warning only ever applies to <code>https://&lt;ip&gt;:8443</code> — never to your actual sites once SSL is installed on them.</p><h2 id="browser-warning-on-your-site" tabindex="-1">Browser warning on your site <a class="header-anchor" href="#browser-warning-on-your-site" aria-label="Permalink to &quot;Browser warning on your site&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common during initial setup</span> New sites receive a temporary self-signed certificate so Nginx can serve HTTPS before a trusted certificate is issued. A browser warning is expected until you install or import a trusted certificate.</p><p><strong>Most likely: SSL just hasn&#39;t been installed for that domain yet.</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssl:status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If the domain isn&#39;t listed, or shows as self-signed, install a trusted certificate after DNS points to the server:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssl:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin@example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>If SSL is installed but the warning persists specifically on <code>www.example.com</code></strong> (while the bare domain works fine, or vice versa), verify both names resolve to the server and re-run AidiPanel&#39;s certificate installation:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssl:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin@example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>If you recently changed DNS or moved servers</strong>, browsers and OSes cache certificate/DNS state — try a hard refresh or a different network/device to rule out local caching before assuming the server is misconfigured.</p><h2 id="challenge-failed" tabindex="-1">&quot;Challenge failed&quot; <a class="header-anchor" href="#challenge-failed" aria-label="Permalink to &quot;&quot;Challenge failed&quot;&quot;">​</a></h2><p><span class="ap-pill ap-pill-common">Common</span> This is Certbot telling you it couldn&#39;t verify domain ownership via the HTTP challenge. Two causes account for nearly all instances of this:</p><p><strong>1. DNS hasn&#39;t actually propagated yet</strong> — go back to <a href="#dns-not-resolving">DNS not resolving</a> above and confirm <code>dig +short example.com</code> returns your server&#39;s IP <em>before</em> retrying <code>ssl:install</code>.</p><p><strong>2. Port 80 isn&#39;t reachable from the internet:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Confirm the firewall allows it</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ufw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 80/tcp</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Confirm Nginx is actually listening on it</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tlnp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :80</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>If you&#39;re on a cloud provider (AWS, DigitalOcean, Hetzner, GCP), also check that provider&#39;s <strong>network-level security group / firewall</strong> — UFW being open on the server doesn&#39;t help if the cloud provider&#39;s firewall in front of it is blocking port 80 separately. This is the single most common miss for people coming from providers with a separate cloud firewall layer.</p><h2 id="too-many-certificates" tabindex="-1">Too many certificates <a class="header-anchor" href="#too-many-certificates" aria-label="Permalink to &quot;Too many certificates&quot;">​</a></h2><p><span class="ap-pill ap-pill-rare">Occasional, usually while testing</span> Let&#39;s Encrypt allows <strong>5 certificates per exact domain name per week</strong>. If you&#39;re testing <code>ssl:install</code> repeatedly (deleting and re-issuing while debugging something else), you can hit this limit surprisingly fast.</p><p>Use the <code>--staging</code> flag while testing, which issues from Let&#39;s Encrypt&#39;s staging environment and doesn&#39;t count against your real limit (staging certs aren&#39;t trusted by browsers, but they confirm the <em>mechanism</em> works):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">certbot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --nginx</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --staging</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Once you&#39;re confident it&#39;ll work, drop <code>--staging</code> and issue for real — that one issuance counts, but you won&#39;t have burned your quota on the debugging attempts.</p><h2 id="certificate-not-renewing-automatically" tabindex="-1">Certificate not renewing automatically <a class="header-anchor" href="#certificate-not-renewing-automatically" aria-label="Permalink to &quot;Certificate not renewing automatically&quot;">​</a></h2><p><span class="ap-pill ap-pill-rare">Rare</span> Renewal is supposed to be silent and automatic. If a certificate is approaching expiry anyway:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Confirm the renewal cron actually exists and is active</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/cron.d/aidipanel</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cron</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Test whether renewal *would* succeed, without actually doing it</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">certbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> renew</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Check what happened on the last attempt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -50</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/aidipanel-certbot.log</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Force it manually right now</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">certbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> renew</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force-renewal</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --nginx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>If <code>--dry-run</code> fails with a DNS or connection error, the cause is the same as <a href="#challenge-failed">Challenge failed</a> above — something changed about DNS or port 80 reachability since the certificate was first issued.</p><h2 id="wildcard-certificate-challenges" tabindex="-1">Wildcard certificate challenges <a class="header-anchor" href="#wildcard-certificate-challenges" aria-label="Permalink to &quot;Wildcard certificate challenges&quot;">​</a></h2><p>If you&#39;re trying to get <code>*.example.com</code> working and hitting issues, remember wildcards <strong>require DNS challenge, not HTTP challenge</strong> — <code>ssl:install</code> doesn&#39;t handle this automatically. See <a href="/docs/guide/ssl#wildcard-certificates">SSL / TLS → Wildcard certificates</a> for the manual Certbot command and the DNS TXT record step it walks you through.</p>`,34)])])}const u=a(t,[["render",l]]);export{g as __pageData,u as default};
